import { vi } from 'vitest';

// Create a factory function to generate fresh mocks for each test
export function createPixiMock() {
  // Create a real canvas element using jsdom's document
  const createMockCanvas = () => {
    const canvas = document.createElement('canvas');
    canvas.width = 400;
    canvas.height = 400;

    // Return the actual canvas element - jsdom will handle getContext
    return canvas;
  };

  // Create mock PIXI objects
  const mockContainer = () => ({
    addChild: vi.fn(),
    removeChild: vi.fn(),
    removeChildren: vi.fn(),
    position: { 
      set: vi.fn(),
      x: 0,
      y: 0
    },
    scale: { 
      set: vi.fn(),
      x: 1,
      y: 1
    },
    pivot: { 
      set: vi.fn(),
      x: 0,
      y: 0
    },
    toLocal: vi.fn((point) => point),
    children: [],
    interactive: true,
    on: vi.fn(),
    off: vi.fn(),
    emit: vi.fn(),
    parent: null,
    visible: true,
    alpha: 1,
    width: 0,
    height: 0,
    destroy: vi.fn(),
  });

  const mockSprite = () => ({
    position: { 
      set: vi.fn(),
      x: 0,
      y: 0
    },
    scale: { 
      set: vi.fn(),
      x: 1,
      y: 1
    },
    pivot: { 
      set: vi.fn(),
      x: 0,
      y: 0
    },
    alpha: 1,
    texture: null,
    destroy: vi.fn(),
    visible: true,
    width: 0,
    height: 0,
  });

  const mockGraphics = () => ({
    clear: vi.fn().mockReturnThis(),
    lineStyle: vi.fn().mockReturnThis(),
    moveTo: vi.fn().mockReturnThis(),
    lineTo: vi.fn().mockReturnThis(),
    beginFill: vi.fn().mockReturnThis(),
    drawRect: vi.fn().mockReturnThis(),
    drawCircle: vi.fn().mockReturnThis(),
    endFill: vi.fn().mockReturnThis(),
    position: { 
      set: vi.fn(),
      x: 0,
      y: 0
    },
    visible: true,
    alpha: 1,
    destroy: vi.fn(),
  });

  const mockText = () => ({
    position: { 
      set: vi.fn(),
      x: 0,
      y: 0
    },
    text: '',
    style: {},
    visible: true,
    alpha: 1,
    destroy: vi.fn(),
  });

  // Create the main Application mock
  const mockApplication = function() {
    const canvas = createMockCanvas();
    const stage = mockContainer();

    // Return the application instance
    const app = {
      init: vi.fn().mockImplementation(async () => {
        // After init, the canvas property should be available
