     8→/**
     9→ * Enumerates the names for the three standard orthogonal views:
    10→ *   - Axial
    11→ *   - Coronal
    12→ *   - Sagittal
    13→ */
    14→enum ViewName {
    15→  Axial = 'axial',
    16→  Coronal = 'coronal',
    17→  Sagittal = 'sagittal',
    18→}
    19→
    20→/**
    21→ * Optional configuration for how each orthogonal viewer is displayed and operated.
    22→ */
    23→interface OrthogonalImageViewerOptions {
    24→  /**
    25→   * Width in pixels for each of the sub-viewers (optional if auto-resizing).
    26→   */
    27→  width?: number;
    28→
    29→  /**
    30→   * Height in pixels for each of the sub-viewers (optional if auto-resizing).
    31→   */
    32→  height?: number;
    33→
    34→  /**
    35→   * Whether to display crosshair lines in the sub-viewers.
    36→   */
    37→  showCrosshair?: boolean;
    38→
    39→  /**
    40→   * Whether to display a slider in each sub-viewer for changing slice indices.
    41→   */
    42→  showSlider?: boolean;
    43→}
    44→
    45→/**
    46→ * Parameters required to instantiate the OrthogonalImageViewer.
    47→ */
    48→interface OrthogonalImageViewerParams {
    49→  /**
    50→   * The DOM container in which this orthogonal viewer's layout will be placed.
    51→   */
    52→  container: HTMLElement;
    53→
    54→  /**
    55→   * The ImageLayer instance that holds the volume data in a VolStack.
    56→   */
    57→  imageLayer: ImageLayer;
    58→
    59→  /**
    60→   * Viewer options for layout or interactive features.
    61→   */
    62→  options?: OrthogonalImageViewerOptions;
    63→}
    64→
    65→/**
    66→ * OrthogonalImageViewer manages three simultaneous SliceViewers (Axial, Coronal, Sagittal),
    67→ * each displaying a different orientation of the same data. The user can interact with
    68→ * any sub-view to change the shared coordinate, updating the other sub-views in sync.
    69→ *
    70→ * All the sub-viewers are arranged in a grid layout. The class handles:
    71→ *   - Creating the DOM elements for each view.
    72→ *   - Initializing and disposing the sub-viewers.
    73→ *   - Synchronizing the position (currentCoord) among the sub-viewers.
    74→ *   - Handling window resize events and re-drawing each view.
    75→ *   - Reactively updating the sub-viewers if the user adjusts slice indices in any one viewer.
    76→ */
    77→export class OrthogonalImageViewer implements ViewerStateInfo {
    78→  /**
    79→   * The current 3D coordinate shared by all sub-viewers. 
    80→   * This is updated whenever one of the SliceViewers changes its currentCoord.
    81→   */
    82→  @observable public currentCoord: number[];
    83→
    84→  /**
    85→   * An observable storing the mouse state: which view's mouse changed,
    86→   * and the image and volume coordinates under the pointer.
    87→   */
    88→  @observable private _mouseState: {
    89→    viewName: string | null;
    90→    imageCoordinate: { x: number; y: number } | null;
    91→    volumeCoordinate: number[] | null;
    92→    worldCoordinate: number[] | null;
    93→  } = {
    94→    viewName: null,
    95→    imageCoordinate: null,
    96→    volumeCoordinate: null,
    97→    worldCoordinate: null
    98→  };
    99→
   100→  // The top-level parameters for container and layer.
   101→  private params: OrthogonalImageViewerParams;
   102→  private container: HTMLElement;
   103→  private imageLayer: ImageLayer;
   104→
   105→  // A dictionary of SliceViewers: keys are "axial", "coronal", "sagittal".
   106→  private sliceViewers: Record<ViewName, SliceViewer>;
   107→
   108→  // A dictionary of AxisSet3D for each standard orientation.
   109→  private axesSets: Record<ViewName, AxisSet3D>;
   110→
   111→  // Additional user-defined options like "showCrosshair" or "showSlider".
   112→  private options: OrthogonalImageViewerOptions;
   113→
   114→  // A dictionary of DOM elements (HTML divs) for each sub-view.
   115→  private viewDivs: Record<ViewName, HTMLElement> = {} as Record<ViewName, HTMLElement>;
   116→
   117→  // Bound method for handling container resize events.
   118→  private handleResizeBound = this.handleResize.bind(this);
   119→
   120→  // A collection of MobX disposers for cleaning up reactive side effects.
   121→  private disposers: IReactionDisposer[] = [];
   122→
   123→  /**
   124→   * Private constructor to force usage of the async factory method `.create()`.
   125→   * 
   126→   * @param params - The container, imageLayer, and optional settings.
   127→   */
   128→  private constructor(params: OrthogonalImageViewerParams) {
   129→    this.params = params;
   130→    this.container = params.container;
   131→    this.imageLayer = params.imageLayer;
   132→    this.options = params.options ?? {};
   133→
   134→    // Predefined orientation sets for each sub-view
   135→    this.axesSets = {
   136→      [ViewName.Axial]: AxisSet3D.AXIAL_LPI,
   137→      [ViewName.Coronal]: AxisSet3D.CORONAL_LIP,
   138→      [ViewName.Sagittal]: AxisSet3D.SAGITTAL_AIL,
   139→    };
   140→
   141→    // Initialize currentCoord to the space's centroid (center of volume).
   142→    const centroid = this.imageLayer.neuroSpace.centroid();
   143→    this.currentCoord = centroid.slice();
   144→
   145→    // Prepare an empty record for the 3 SliceViewers
   146→    this.sliceViewers = {} as Record<ViewName, SliceViewer>;
   147→
   148→    makeObservable(this);
   149→  }
   150→
   151→  /**
   152→   * Creates an OrthogonalImageViewer, asynchronously building its sub-viewers.
   153→   * 
   154→   * @param params - Contains the container HTMLElement, imageLayer, and viewer options.
   155→   * @returns A fully-initialized instance of OrthogonalImageViewer.
   156→   */
   157→  public static async create(
   158→    params: OrthogonalImageViewerParams
   159→  ): Promise<OrthogonalImageViewer> {
   160→    const viewer = new OrthogonalImageViewer(params);
   161→    await viewer.initialize();
   162→    return viewer;
   163→  }
   164→
   165→  /**
   166→   * Main async init routine that sets up the layout grid, creates each SliceViewer,
   167→   * and wires up MobX reactions.
   168→   */
   169→  private async initialize(): Promise<void> {
   170→    // 1) Create the layout DOM structure
   171→    await this.initializeLayout();
   172→
   173→    // 2) Instantiate each of the three sub-viewers
   174→    await this.initializeViewers();
   175→
   176→    // 3) Set up cross-view property syncing
   177→    this.setupReactions();
   178→
   179→    // 4) Perform initial sizing
   180→    this.handleResize();
   181→  }
   182→
   183→  /**
   184→   * Creates HTML divs for each orientation (axial, coronal, sagittal) inside a 2x2 CSS grid.
   185→   */
   186→  private async initializeLayout(): Promise<void> {
   187→    // Create sub-viewer divs
   188→    const axialDiv = document.createElement('div');
   189→    const coronalDiv = document.createElement('div');
   190→    const sagittalDiv = document.createElement('div');
   191→
   192→    // Define a style object to share across the sub-view divs
   193→    const viewStyle: Partial<CSSStyleDeclaration> = {
   194→      width: '100%',
   195→      height: '100%',
   196→      position: 'relative',
   197→      overflow: 'hidden',
   198→    };
   199→
   200→    // Apply the styles to each sub-view div
   201→    Object.assign(axialDiv.style, viewStyle);
   202→    Object.assign(coronalDiv.style, viewStyle);
   203→    Object.assign(sagittalDiv.style, viewStyle);
   204→
   205→    // Name each div for a CSS grid area
   206→    axialDiv.style.gridArea = 'axial';
   207→    coronalDiv.style.gridArea = 'coronal';
   208→    sagittalDiv.style.gridArea = 'sagittal';
   209→
   210→    // The container is turned into a grid layout with 2 rows × 2 columns.
   211→    // 
   212→    //  +--------------+--------------+
   213→    //  | axial (col1) | coronal (col2)
   214→    //  +--------------+--------------+
   215→    //  | axial (col1) | sagittal(col2)
   216→    //  +--------------+--------------+
   217→    //
   218→    //  So axial is tall, occupying left side in both rows, while coronal/sagittal share the top/bottom of right side.
   219→    const viewerContainer = this.container;
   220→    viewerContainer.style.display = 'grid';
   221→    viewerContainer.style.gridTemplateAreas = `
   222→      "axial coronal"
   223→      "axial sagittal"
   224→    `;
   225→    viewerContainer.style.gridTemplateColumns = '1fr 1fr';
   226→    viewerContainer.style.gridTemplateRows = '1fr 1fr';
   227→    viewerContainer.style.gap = '2px';
   228→
   229→    // Add the new sub-view divs to the container
   230→    viewerContainer.appendChild(axialDiv);
   231→    viewerContainer.appendChild(coronalDiv);
   232→    viewerContainer.appendChild(sagittalDiv);
   233→
   234→    // Store references in a dictionary keyed by the ViewName enum
   235→    this.viewDivs = {
   236→      [ViewName.Axial]: axialDiv,
   237→      [ViewName.Coronal]: coronalDiv,
   238→      [ViewName.Sagittal]: sagittalDiv,
   239→    };
   240→  }
   241→
   242→  /**
   243→   * Creates a SliceViewer for each orientation (axial, coronal, sagittal),
   244→   * connecting them to the same ImageLayer. Also sets up reaction watchers
   245→   * to keep them in sync.
   246→   */
   247→  private async initializeViewers(): Promise<void> {
   248→    // For each axis set in this.axesSets, we create a corresponding SliceViewer
   249→    const creationPromises = Object.entries(this.axesSets).map(async ([viewKey, axesSet]) => {
   250→      const viewName = viewKey as ViewName;
   251→      const domElement = this.viewDivs[viewName];
   252→
   253→      // Instantiate
   254→      const viewer = await SliceViewer.create(domElement, this.imageLayer, axesSet, {
   255→        showCrosshair: this.options.showCrosshair,
   256→        showSlider: this.options.showSlider,
   257→      });
   258→      this.sliceViewers[viewName] = viewer;
   259→
   260→      // Observe changes in each viewer's internal state
   261→      this.setupViewerReactions(viewName, viewer);
   262→
   263→    });
   264→
   265→    // Wait for all three sub-viewers to be created
   266→    await Promise.all(creationPromises);
   267→
   268→    // After creation, set them all to the same initial currentCoord
   269→    this.setAllViewersPosition(this.currentCoord);
   270→  }
   271→
   272→  /**
   273→   * Sets up a global reaction so if our shared currentCoord changes, 
   274→   * all sub-viewers are updated to match.
