/**
 * Fit content to screen + flip Y scale
 */
private fitContainerToScreen(): void {
  if (!this.mainContainer.children.length) {
    console.warn('No content to fit');
    return;
  }

  const contentBounds = this.mainContainer.getLocalBounds();
  const rendererWidth = this.app.renderer.width;
  const rendererHeight = this.app.renderer.height;

  const scaleX = rendererWidth / contentBounds.width;
  const scaleY = rendererHeight / contentBounds.height;
  const scale = Math.min(scaleX, scaleY);

  // Center pivot
  this.mainContainer.pivot.set(
    contentBounds.x + contentBounds.width / 2,
    contentBounds.y + contentBounds.height / 2
  );
  this.mainContainer.position.set(rendererWidth / 2, rendererHeight / 2);

  // Flip Y
  this.mainContainer.scale.x = scale;
