    28→function clusteredNeuroVolFromDense(
    29→  vol: NeuroVol,
    30→  labelMap?: Map<number, string>
    31→): ClusteredNeuroVol {
    32→  const data = vol.getData();
    33→  
    34→  // Find non-zero voxels (mask)
    35→  const maskIndices: number[] = [];
    36→  const clusterIds: number[] = [];
    37→  
    38→  for (let i = 0; i < data.length; i++) {
    39→    if (data[i] !== 0) {
    40→      maskIndices.push(i);
    41→      clusterIds.push(data[i]);
    42→    }
    43→  }
    44→  
    45→  // Create mask
    46→  const maskData = new Uint8Array(data.length);
    47→  for (const idx of maskIndices) {
    48→    maskData[idx] = 1;
    49→  }
    50→  const mask = new LogicalNeuroVol(vol.space, maskData);
    51→  
    52→  // Create label map if not provided
    53→  const finalLabelMap: Record<string, number> = {};
    54→  if (!labelMap) {
    55→    const uniqueIds = Array.from(new Set(clusterIds));
    56→    for (const id of uniqueIds) {
    57→      finalLabelMap[`Cluster${id}`] = id;
    58→    }
    59→  } else {
    60→    // Convert Map to object - Map has id as key and name as value
    61→    for (const [id, name] of labelMap) {
    62→      finalLabelMap[name] = id;
    63→    }
    64→  }
    65→  
