    81→  x: NeuroVol | NeuroVec,
    82→  indices: Uint32Array | Int32Array,
    83→  blockIds: Int32Array
    84→): Array<NeuroVol | NeuroVec> {
    85→  if (indices.length !== blockIds.length) {
    86→    throw new ValueError('indices and blockIds must have same length');
    87→  }
    88→
    89→  const uniqueBlocks = Array.from(new Set(blockIds));
    90→  const blocks: Array<NeuroVol | NeuroVec> = [];
    91→
    92→  for (const blockId of uniqueBlocks) {
    93→    // Get indices for this block
    94→    const blockIndices: number[] = [];
