    96→      if (blockIds[i] === blockId) {
    97→        blockIndices.push(indices[i]);
    98→      }
    99→    }
   100→
   101→    if ('getVolume' in x) {
   102→      // NeuroVec case
   103→      const vec = x as NeuroVec;
   104→      
   105→      // Create array to hold time series for this block
   106→      const nTimepoints = vec.dim[3]; // Time is the 4th dimension (X,Y,Z,T)
   107→      const blockSeries = new Float32Array(blockIndices.length * nTimepoints);
   108→      
   109→      // Extract time series for each voxel in the block
   110→      const spatialDims = vec.dim.slice(0, 3); // X,Y,Z dimensions
   111→      const spatialSize = spatialDims.reduce((a, b) => a * b, 1);
