   151→                       [...vec.origin.slice(1), vec.origin[0]]),
   152→        voxelDataMap
   153→      );
   154→      
   155→      blocks.push(blockVec);
   156→      
   157→    } else {
   158→      // NeuroVol case
   159→      const vol = x as NeuroVol;
   160→      const blockData = new Float32Array(blockIndices.length);
   161→      
