   184→/**
   185→ * Split data into ROIs based on cluster labels.
   186→ * 
   187→ * Creates a list of ROIVol objects, one for each cluster, containing
   188→ * the data values from the input volume/vector.
   189→ * 
   190→ * @param x - The data to split
   191→ * @param clusters - Volume containing integer cluster labels
   192→ * @returns List of ROI volumes, one for each cluster
   193→ */
   194→export function splitClusters(
   195→  x: NeuroVol | NeuroVec,
   196→  clusters: ClusteredNeuroVol | NeuroVol
   197→): ROIVol[] {
   198→  // For NeuroVec, compare spatial dimensions only
   199→  if ('getVolume' in x) {
   200→    const vec = x as NeuroVec;
   201→    const spatialDims = vec.dim.slice(0, 3); // X,Y,Z dimensions
   202→    if (!spatialDims.every((d, i) => d === clusters.space.dim[i])) {
   203→      throw new ValueError('x and clusters must have same spatial dimensions');
   204→    }
   205→  } else {
   206→    const vol = x as NeuroVol;
   207→    if (!vol.space.isEqualTo(clusters.space)) {
   208→      throw new ValueError('x and clusters must have same space');
   209→    }
   210→  }
   211→
   212→  // Get cluster labels
   213→  let clusterData: TypedArray;
   214→  let uniqueLabels: number[];
   215→  
   216→  if (clusters instanceof ClusteredNeuroVol) {
   217→    uniqueLabels = Array.from(Object.values(clusters.labelMap));
   218→    clusterData = clusters.asDense().getData();
   219→  } else {
   220→    clusterData = clusters.getData();
   221→    const labelSet = new Set<number>();
   222→    for (let i = 0; i < clusterData.length; i++) {
   223→      if (clusterData[i] > 0) {
   224→        labelSet.add(clusterData[i]);
   225→      }
   226→    }
   227→    uniqueLabels = Array.from(labelSet);
   228→  }
   229→
   230→  const rois: ROIVol[] = [];
   231→
   232→  for (const label of uniqueLabels) {
   233→    if (label === 0) continue; // Skip background
   234→
   235→    // Get voxel coordinates for this cluster
   236→    const coords: Array<[number, number, number]> = [];
   237→    const values: number[] = [];
   238→    
   239→    for (let z = 0; z < clusters.space.dim[2]; z++) {
   240→      for (let y = 0; y < clusters.space.dim[1]; y++) {
   241→        for (let xCoord = 0; xCoord < clusters.space.dim[0]; xCoord++) {
   242→          const idx = clusters.space.gridToIndex([xCoord, y, z]);
   243→          if (clusterData[idx] === label) {
   244→            coords.push([xCoord, y, z]);
   245→            
   246→            // Extract data value
   247→            if ('getVolume' in x) {
   248→              // For NeuroVec, average time series
   249→              const vec = x as NeuroVec;
   250→              let sum = 0;
   251→              const nTimepoints = vec.dim[3]; // Time is the 4th dimension
   252→              for (let t = 0; t < nTimepoints; t++) {
   253→                sum += vec.getAt(xCoord, y, z, t);
   254→              }
   255→              values.push(sum / nTimepoints);
   256→            } else {
   257→              // For NeuroVol, extract value directly
   258→              const vol = x as NeuroVol;
   259→              values.push(vol.getAt(xCoord, y, z));
   260→            }
   261→          }
   262→        }
   263→      }
   264→    }
   265→
   266→    // Skip empty clusters
   267→    if (coords.length === 0) {
   268→      continue;
   269→    }
   270→    
   271→    // Create ROIVol
   272→    const data = new Float32Array(values);
   273→    
   274→    const space = clusters instanceof ClusteredNeuroVol ? clusters.space : clusters.space;
   275→    const roi = new ROIVol(data, space, coords);
   276→    rois.push(roi);
   277→  }
   278→
   279→  return rois;
   280→}
