   292→export function splitFill(
   293→  x: NeuroVec,
   294→  fac: Int32Array | Float32Array
   295→): Map<number, NeuroVec> {
   296→  const nVolumes = x.dim[3]; // Time is the 4th dimension (X,Y,Z,T)
   297→  
   298→  if (fac.length !== nVolumes) {
   299→    throw new ValueError(`Length of factor (${fac.length}) must equal number of volumes (${nVolumes})`);
   300→  }
   301→
   302→  const levels = Array.from(new Set(fac));
   303→  const result = new Map<number, NeuroVec>();
   304→
   305→  for (const level of levels) {
   306→    // Get indices for this level
   307→    const levelIndices: number[] = [];
   308→    for (let i = 0; i < fac.length; i++) {
   309→      if (fac[i] === level) {
   310→        levelIndices.push(i);
   311→      }
   312→    }
   313→
   314→    const nLevelVolumes = levelIndices.length;
   315→
   316→    if (x instanceof SparseNeuroVec) {
   317→      // For sparse vectors, we need to handle the Map-based data structure
   318→      // Create new space with updated time dimension (X,Y,Z,T ordering)
   319→      const newDim = [...x.dim.slice(0, 3), nLevelVolumes];
   320→      const newSpace = new NeuroSpace(newDim, x.spacing, x.origin);
   321→      
   322→      // Convert to Map format for SparseNeuroVec
   323→      const voxelDataMap = new Map<number, number[]>();
   324→      const sparseVec = x as SparseNeuroVec;
   325→      
   326→      // Copy only the selected time points for each voxel
   327→      for (const [voxelIdx, timeSeries] of sparseVec.getData()) {
   328→        const newTimeSeries: number[] = [];
   329→        for (const timeIdx of levelIndices) {
   330→          if (timeIdx < timeSeries.length) {
   331→            newTimeSeries.push(timeSeries[timeIdx]);
   332→          }
   333→        }
   334→        voxelDataMap.set(voxelIdx, newTimeSeries);
   335→      }
   336→      
   337→      const levelVec = new SparseNeuroVec(newSpace, voxelDataMap);
   338→      result.set(level, levelVec);
   339→    } else {
   340→      // For dense, extract the relevant volumes (X,Y,Z,T ordering)
   341→      const spatialSize = x.dim[0] * x.dim[1] * x.dim[2]; // X*Y*Z
   342→      const subsetData = new Float32Array(spatialSize * nLevelVolumes);
   343→      
   344→      // Copy data for selected time points
   345→      const srcData = x.getData();
   346→      for (let i = 0; i < spatialSize; i++) {
   347→        for (let t = 0; t < nLevelVolumes; t++) {
   348→          const srcTimeIdx = levelIndices[t];
   349→          const srcIdx = i + srcTimeIdx * spatialSize;
   350→          const dstIdx = i + t * spatialSize;
   351→          subsetData[dstIdx] = srcData[srcIdx];
   352→        }
   353→      }
   354→
   355→      // Create new space with updated time dimension (X,Y,Z,T ordering)
   356→      const newDim = [...x.dim.slice(0, 3), nLevelVolumes];
   357→      const newSpace = new NeuroSpace(newDim, x.spacing, x.origin);
   358→      
   359→      const levelVec = new Float32NeuroVec(newSpace, subsetData);
   360→      result.set(level, levelVec);
   361→    }
   362→  }
   363→
   364→  return result;
   365→}
