   383→): NeuroVol {
   384→  const nVolumes = x.dim[3]; // Time is the 4th dimension (X,Y,Z,T)
   385→  
   386→  if (fac.length !== nVolumes) {
   387→    throw new ValueError(`Length of factor (${fac.length}) must equal number of volumes (${nVolumes})`);
   388→  }
   389→
   390→  // Create 3D space for output volume (X,Y,Z)
   391→  const volSpace = new NeuroSpace(
   392→    x.dim.slice(0, 3),
   393→    x.spacing.slice(0, 3),
   394→    x.origin.slice(0, 3)
   395→  );
   396→
   397→  // Get unique levels
   398→  const uniqueLevels = Array.from(new Set(fac));
   399→  
   400→  if ('getData' in x && x.getData && !('voxelData' in x)) { // Check if it's a dense vector
   401→    // Initialize output array
   402→    const outData = new Float32Array(volSpace.size);
   403→    const srcData = x.getData();
   404→    
   405→    // Process each voxel
   406→    const spatialSize = volSpace.size;
   407→    for (let voxIdx = 0; voxIdx < spatialSize; voxIdx++) {
   408→      const reducedValues: number[] = [];
   409→      
   410→      // Apply function to each level
   411→      for (const level of uniqueLevels) {
   412→        const levelValues: number[] = [];
   413→        
