   442→      const reducedValues: number[] = [];
   443→      
   444→      // Apply function to each level
   445→      for (const level of uniqueLevels) {
   446→        const levelValues: number[] = [];
   447→        
   448→        for (let t = 0; t < nVolumes; t++) {
   449→          if (fac[t] === level && t < timeSeries.length) {
   450→            levelValues.push(timeSeries[t]);
   451→          }
   452→        }
   453→        
   454→        if (levelValues.length > 0) {
   455→          reducedValues.push(FUN(new Float32Array(levelValues)));
   456→        }
   457→      }
