   528→        // Extract values for this level
   529→        const levelValues = new Float32Array(levelIndices.length);
   530→        for (let i = 0; i < levelIndices.length; i++) {
   531→          // For X,Y,Z,T ordering: index = voxIdx + timeIdx * spatialSize
   532→          levelValues[i] = scaledData[voxIdx + levelIndices[i] * spatialSize];
   533→        }
   534→        
   535→        // Compute mean and SD
   536→        let mean = 0;
   537→        if (center) {
   538→          mean = levelValues.reduce((a, b) => a + b, 0) / levelValues.length;
   539→        }
   540→        
   541→        let sd = 1;
   542→        if (scale) {
   543→          const variance = levelValues.reduce((sum, val) => {
   544→            const diff = val - mean;
   545→            return sum + diff * diff;
   546→          }, 0) / (levelValues.length - 1);
   547→          sd = Math.sqrt(variance);
   548→          if (sd === 0) sd = 1; // Avoid division by zero
   549→        }
   550→        
   551→        // Apply scaling
   552→        for (let i = 0; i < levelIndices.length; i++) {
   553→          // For X,Y,Z,T ordering: index = voxIdx + timeIdx * spatialSize
   554→          const idx = voxIdx + levelIndices[i] * spatialSize;
   555→          scaledData[idx] = (scaledData[idx] - mean) / sd;
   556→        }
   557→      }
   558→    }
   559→    
   560→    return new Float32NeuroVec(x.space, scaledData);
   561→    
   562→  } else if (x instanceof SparseNeuroVec) {
   563→    // Handle sparse case
   564→    const sparseVec = x as SparseNeuroVec;
   565→    const voxelDataMap = new Map<number, number[]>();
   566→    
   567→    // Copy original data
   568→    for (const [voxIdx, timeSeries] of sparseVec.getData()) {
   569→      voxelDataMap.set(voxIdx, [...timeSeries]);
   570→    }
   571→    
   572→    // Process each level
   573→    for (const level of uniqueLevels) {
   574→      const levelIndices: number[] = [];
   575→      for (let i = 0; i < fac.length; i++) {
   576→        if (fac[i] === level) {
   577→          levelIndices.push(i);
   578→        }
   579→      }
   580→      
   581→      if (levelIndices.length < 2) continue;
   582→      
   583→      // Process each voxel
   584→      for (const [voxIdx, timeSeries] of voxelDataMap) {
   585→        // Extract values for this level
   586→        const levelValues = new Float32Array(levelIndices.length);
   587→        for (let i = 0; i < levelIndices.length; i++) {
   588→          levelValues[i] = timeSeries[levelIndices[i]];
   589→        }
   590→        
   591→        // Compute mean and SD
   592→        let mean = 0;
   593→        if (center) {
   594→          mean = levelValues.reduce((a, b) => a + b, 0) / levelValues.length;
   595→        }
   596→        
   597→        let sd = 1;
   598→        if (scale) {
   599→          const variance = levelValues.reduce((sum, val) => {
   600→            const diff = val - mean;
   601→            return sum + diff * diff;
   602→          }, 0) / (levelValues.length - 1);
   603→          sd = Math.sqrt(variance);
   604→          if (sd === 0) sd = 1;
   605→        }
   606→        
   607→        // Apply scaling
   608→        for (let i = 0; i < levelIndices.length; i++) {
   609→          timeSeries[levelIndices[i]] = (levelValues[i] - mean) / sd;
   610→        }
   611→      }
   612→    }
   613→    
   614→    return new SparseNeuroVec(x.space, voxelDataMap);
   615→  }
   616→  
   617→  throw new ValueError('Unsupported NeuroVec type');
   618→}
   619→
   620→/**
   621→ * Partition a volume into k regions using clustering.
   622→ * 
   623→ * Uses clustering algorithms to partition the brain volume into
   624→ * k distinct regions based on voxel values.
   625→ * 
   626→ * @param x - The volume to partition
   627→ * @param k - Number of partitions/clusters
   628→ * @param method - Clustering method (currently only "kmeans")
   629→ * @param mask - Optional mask to restrict clustering to specific voxels
   630→ * @returns Clustered volume with partition labels
   631→ */
   632→export function partition(
   633→  x: NeuroVol,
   634→  k: number,
   635→  method: string = 'kmeans',
   636→  mask?: LogicalNeuroVol
   637→): ClusteredNeuroVol {
   638→  // Get mask - either provided or non-zero voxels
   639→  let maskData: Uint8Array;
   640→  if (mask) {
   641→    maskData = mask.getData() as Uint8Array;
   642→  } else {
   643→    const data = x.getData();
   644→    maskData = new Uint8Array(data.length);
   645→    for (let i = 0; i < data.length; i++) {
   646→      maskData[i] = data[i] !== 0 ? 1 : 0;
   647→    }
   648→  }
   649→
   650→  // Get masked values
   651→  const maskIndices: number[] = [];
   652→  const values: number[] = [];
   653→  for (let i = 0; i < maskData.length; i++) {
   654→    if (maskData[i]) {
   655→      maskIndices.push(i);
   656→      values.push(x.getData()[i]);
   657→    }
   658→  }
   659→
   660→  if (values.length < k) {
   661→    throw new ValueError(`Number of non-zero voxels (${values.length}) is less than k (${k})`);
   662→  }
   663→
   664→  if (method === 'kmeans') {
   665→    // Simple k-means implementation
   666→    const labels = simpleKMeans(values, k);
   667→    
   668→    // Create label array
   669→    const labelArray = new Float32Array(x.space.size);
   670→    for (let i = 0; i < maskIndices.length; i++) {
   671→      labelArray[maskIndices[i]] = labels[i] + 1; // 1-indexed
   672→    }
   673→    
   674→    // Create label map
   675→    const labelMap = new Map<number, string>();
   676→    for (let i = 1; i <= k; i++) {
   677→      labelMap.set(i, `Cluster${i}`);
   678→    }
   679→    
   680→    // Create clustered volume
   681→    const labelVol = new FloatNeuroVol(x.space, labelArray);
   682→    return clusteredNeuroVolFromDense(labelVol, labelMap);
   683→  } else {
   684→    throw new ValueError(`Unknown method: ${method}`);
   685→  }
   686→}
   687→
   688→/**
   689→ * Simple k-means clustering implementation.
   690→ * For production use, consider using a proper ML library.
   691→ */
   692→function simpleKMeans(values: number[], k: number): number[] {
   693→  const n = values.length;
   694→  const labels = new Array(n).fill(0);
   695→  
   696→  // Initialize centers randomly
   697→  const centers = new Float32Array(k);
   698→  const indices = new Set<number>();
   699→  while (indices.size < k) {
   700→    indices.add(Math.floor(Math.random() * n));
   701→  }
   702→  let i = 0;
   703→  for (const idx of indices) {
   704→    centers[i++] = values[idx];
   705→  }
   706→  
   707→  // Iterate until convergence
   708→  let changed = true;
   709→  let iterations = 0;
   710→  const maxIterations = 100;
   711→  
   712→  while (changed && iterations < maxIterations) {
   713→    changed = false;
   714→    
   715→    // Assign points to nearest center
   716→    for (let i = 0; i < n; i++) {
   717→      let minDist = Infinity;
   718→      let bestLabel = 0;
   719→      
   720→      for (let j = 0; j < k; j++) {
   721→        const dist = Math.abs(values[i] - centers[j]);
   722→        if (dist < minDist) {
   723→          minDist = dist;
   724→          bestLabel = j;
   725→        }
   726→      }
   727→      
   728→      if (labels[i] !== bestLabel) {
   729→        labels[i] = bestLabel;
   730→        changed = true;
   731→      }
   732→    }
   733→    
   734→    // Update centers
   735→    const counts = new Array(k).fill(0);
   736→    centers.fill(0);
   737→    
   738→    for (let i = 0; i < n; i++) {
   739→      centers[labels[i]] += values[i];
   740→      counts[labels[i]]++;
   741→    }
   742→    
   743→    for (let j = 0; j < k; j++) {
   744→      if (counts[j] > 0) {
   745→        centers[j] /= counts[j];
   746→      }
   747→    }
   748→    
   749→    iterations++;
   750→  }
   751→  
   752→  return labels;
   753→}
   754→
   755→/**
   756→ * Map values in a volume using a lookup table.
   757→ * 
   758→ * Replaces values in the volume according to a lookup map.
   759→ * 
   760→ * @param x - The volume to transform
   761→ * @param lookup - Map of old values to new values
   762→ * @returns Volume with mapped values
   763→ */
   764→export function mapValues(
   765→  x: NeuroVol,
   766→  lookup: Map<number, number>
   767→): NeuroVol {
   768→  if (x instanceof SparseNeuroVol) {
   769→    // For sparse volumes, we need to work with the sparse data structure
   770→    const sparseVol = x as SparseNeuroVol;
   771→    const indices: number[] = [];
   772→    const values: number[] = [];
   773→    
   774→    // Get the full data to find sparse values
   775→    const data = sparseVol.getData();
   776→    for (let i = 0; i < data.length; i++) {
   777→      if (data[i] !== 0) { // Non-default value
   778→        const newVal = lookup.get(data[i]);
   779→        const mappedVal = newVal !== undefined ? newVal : data[i];
   780→        if (mappedVal !== 0) { // Only store non-default mapped values
   781→          indices.push(i);
   782→          values.push(mappedVal);
   783→        }
   784→      }
   785→    }
   786→    
   787→    return new SparseNeuroVol(x.space, 'float32', 0, indices, values);
   788→  } else {
   789→    // For dense volumes
   790→    const data = x.getData();
   791→    const mappedData = new Float32Array(data.length);
   792→    
   793→    for (let i = 0; i < data.length; i++) {
   794→      const newVal = lookup.get(data[i]);
   795→      mappedData[i] = newVal !== undefined ? newVal : data[i];
   796→    }
   797→    
   798→    // Preserve exact type
   799→    if (x instanceof FloatNeuroVol) {
   800→      return new FloatNeuroVol(x.space, mappedData);
   801→    } else {
   802→      return new (x.constructor as any)(x.space, mappedData);
   803→    }
   804→  }
   805→}
   806→
   807→/**
   808→ * Calculate centroids for each cluster.
   809→ * 
   810→ * Computes the centroid (center point) of each cluster using
   811→ * the specified method.
   812→ * 
   813→ * @param x - Clustered volume
   814→ * @param method - Method for computing centroids ("center_of_mass" or "median")
   815→ * @returns Map of cluster labels to centroid coordinates
   816→ */
   817→export function centroids(
   818→  x: ClusteredNeuroVol,
   819→  method: string = 'center_of_mass'
   820→): Map<number, [number, number, number]> {
   821→  if (method !== 'center_of_mass' && method !== 'median') {
   822→    throw new ValueError(`Unknown method: ${method}`);
   823→  }
   824→  
   825→  const result = new Map<number, [number, number, number]>();
   826→  const labels = Array.from(Object.values(x.labelMap));
   827→  const clusterData = x.asDense().getData();
   828→  
   829→  for (const label of labels) {
   830→    if (label === 0) continue; // Skip background
   831→    
   832→    const coords: Array<[number, number, number]> = [];
   833→    
   834→    // Find all voxels for this cluster
   835→    for (let z = 0; z < x.space.dim[2]; z++) {
   836→      for (let y = 0; y < x.space.dim[1]; y++) {
   837→        for (let x_coord = 0; x_coord < x.space.dim[0]; x_coord++) {
   838→          const idx = x.space.gridToIndex([x_coord, y, z]);
   839→          if (clusterData[idx] === label) {
   840→            coords.push([x_coord, y, z]);
   841→          }
   842→        }
   843→      }
   844→    }
   845→    
   846→    if (coords.length === 0) continue;
   847→    
   848→    if (method === 'center_of_mass') {
   849→      // Compute mean of coordinates
   850→      let sumX = 0, sumY = 0, sumZ = 0;
   851→      for (const [x, y, z] of coords) {
   852→        sumX += x;
   853→        sumY += y;
   854→        sumZ += z;
   855→      }
   856→      result.set(label, [
   857→        sumX / coords.length,
   858→        sumY / coords.length,
   859→        sumZ / coords.length
   860→      ]);
   861→    } else if (method === 'median') {
   862→      // Compute median of coordinates
   863→      const xCoords = coords.map(c => c[0]).sort((a, b) => a - b);
   864→      const yCoords = coords.map(c => c[1]).sort((a, b) => a - b);
   865→      const zCoords = coords.map(c => c[2]).sort((a, b) => a - b);
   866→      
   867→      const mid = Math.floor(coords.length / 2);
   868→      result.set(label, [
   869→        coords.length % 2 === 0 
   870→          ? (xCoords[mid - 1] + xCoords[mid]) / 2 
   871→          : xCoords[mid],
   872→        coords.length % 2 === 0 
   873→          ? (yCoords[mid - 1] + yCoords[mid]) / 2 
   874→          : yCoords[mid],
   875→        coords.length % 2 === 0 
   876→          ? (zCoords[mid - 1] + zCoords[mid]) / 2 
   877→          : zCoords[mid]
   878→      ]);
   879→    }
   880→  }
   881→  
   882→  return result;
   883→}
   884→
   885→/**
   886→ * Common statistical reduction functions
   887→ */
   888→export const StatFunctions = {
   889→  mean: (values: Float32Array): number => {
   890→    return values.reduce((a, b) => a + b, 0) / values.length;
   891→  },
   892→  
   893→  sum: (values: Float32Array): number => {
   894→    return values.reduce((a, b) => a + b, 0);
   895→  },
   896→  
   897→  min: (values: Float32Array): number => {
   898→    return Math.min(...values);
   899→  },
   900→  
   901→  max: (values: Float32Array): number => {
   902→    return Math.max(...values);
   903→  },
   904→  
   905→  std: (values: Float32Array): number => {
   906→    const mean = StatFunctions.mean(values);
   907→    const variance = values.reduce((sum, val) => {
   908→      const diff = val - mean;
   909→      return sum + diff * diff;
   910→    }, 0) / (values.length - 1);
   911→    return Math.sqrt(variance);
   912→  },
   913→  
   914→  median: (values: Float32Array): number => {
   915→    const sorted = Array.from(values).sort((a, b) => a - b);
   916→    const mid = Math.floor(sorted.length / 2);
   917→    return sorted.length % 2 === 0
   918→      ? (sorted[mid - 1] + sorted[mid]) / 2
   919→      : sorted[mid];
   920→  }
   921→};

