      data[0] = 1;  // (0,0,0)
      data[1] = 1;  // (1,0,0)
      data[2] = 1;  // (2,0,0)
      data[3] = 1;  // (3,0,0)
      data[4] = 1;  // (4,0,0)

      const labelMap = new Map<number, string>([[1, 'Line']]);
      const vol = new FloatNeuroVol(
