content.content:
     1→/**
     2→ * Orthogonal slice extraction for neuroimaging volumes.
     3→ * 
     4→ * This module provides functionality to extract orthogonal slices (axial, sagittal, coronal)
     5→ * from 3D neuroimaging volumes at specified world-space coordinates.
     6→ */
     7→
     8→import { NeuroVol } from './NeuroVol';
     9→import { NeuroSlice } from './NeuroSlice';
    10→import { AxisSet3D } from '../geometry/Axis';
    11→
    12→/**
    13→ * Extract orthogonal slices from a volume at a given world-space point.
    14→ * 
    15→ * This function extracts axial, sagittal, and/or coronal slices from a 3D
    16→ * neuroimaging volume at the specified world-space coordinate.
    17→ * 
    18→ * @param vol - The 3D volume to extract slices from
    19→ * @param worldPoint - World-space coordinates [x, y, z] at which to extract slices
    20→ * @param sliceTypes - Array of slice types to extract. Valid values are 'axial', 'sagittal', 'coronal'.
    21→ *                     If not provided, all three slice types are extracted.
    22→ * @returns Object mapping slice type names to NeuroSlice objects
    23→ * @throws Error if worldPoint is outside volume bounds or has wrong dimensions
    24→ * @throws Error if vol is not a 3D volume
    25→ * 
    26→ * @example
    27→ * ```typescript
    28→ * // Extract all orthogonal slices at world point (10, 20, 30)
    29→ * const slices = extractOrthogonalSlices(vol, [10, 20, 30]);
    30→ * const axialSlice = slices.axial;
    31→ * 
    32→ * // Extract only sagittal slice
    33→ * const slices = extractOrthogonalSlices(vol, [10, 20, 30], ['sagittal']);
    34→ * const sagittalSlice = slices.sagittal;
    35→ * ```
    36→ */
    37→export function extractOrthogonalSlices(
    38→  vol: NeuroVol,
    39→  worldPoint: number[],
    40→  sliceTypes?: Array<'axial' | 'sagittal' | 'coronal'>
    41→): Record<string, NeuroSlice> {
    42→  // Validate volume dimensions
    43→  if (vol.dim.length !== 3) {
    44→    throw new Error('Volume must be 3-dimensional');
    45→  }
    46→
    47→  // Validate world point
    48→  if (worldPoint.length !== 3) {
    49→    throw new Error('worldPoint must be a 3-element array');
    50→  }
    51→
    52→  // Convert world coordinates to grid indices
    53→  const gridPoint = vol.space.coordToGrid(worldPoint);
    54→
    55→  // Check bounds
    56→  for (let i = 0; i < 3; i++) {
    57→    if (gridPoint[i] < 0 || gridPoint[i] >= vol.dim[i]) {
    58→      throw new Error(
    59→        `World point [${worldPoint.join(', ')}] is outside volume bounds. ` +
    60→        `Grid index ${gridPoint[i]} is outside range [0, ${vol.dim[i] - 1}] for axis ${i}`
    61→      );
    62→    }
    63→  }
    64→
    65→  // Default to all slice types if not specified
    66→  const types = sliceTypes || ['axial', 'sagittal', 'coronal'];
    67→
    68→  // Validate slice types
    69→  const validTypes = new Set(['axial', 'sagittal', 'coronal']);
    70→  for (const sliceType of types) {
    71→    if (!validTypes.has(sliceType)) {
    72→      throw new Error(
    73→        `Invalid slice type: ${sliceType}. Valid types are: ${Array.from(validTypes).join(', ')}`
    74→      );
    75→    }
    76→  }
    77→
    78→  // Extract requested slices
    79→  const result: Record<string, NeuroSlice> = {};
    80→
    81→  if (types.includes('axial')) {
    82→    result.axial = extractAxialSlice(vol, worldPoint);
    83→  }
    84→
    85→  if (types.includes('sagittal')) {
    86→    result.sagittal = extractSagittalSlice(vol, worldPoint);
    87→  }
    88→
    89→  if (types.includes('coronal')) {
    90→    result.coronal = extractCoronalSlice(vol, worldPoint);
    91→  }
    92→
    93→  return result;
    94→}
    95→
    96→/**
    97→ * Extract an axial slice at the given world-space point.
    98→ * 
    99→ * An axial slice is a horizontal slice that shows left-right and 
   100→ * anterior-posterior dimensions.
   101→ * 
   102→ * @param vol - The 3D volume to extract slice from
   103→ * @param worldPoint - World-space coordinates [x, y, z] at which to extract slice
   104→ * @returns 2D axial slice at the specified z-coordinate
   105→ * 
   106→ * @remarks
   107→ * The axial slice is extracted along the z-axis (inferior-superior axis),
   108→ * showing the x-y plane (left-right and anterior-posterior).
   109→ */
   110→export function extractAxialSlice(vol: NeuroVol, worldPoint: number[]): NeuroSlice {
   111→  // Convert world to grid coordinates
   112→  const gridPoint = vol.space.coordToGrid(worldPoint);
