    21→  private _inverseTrans: Matrix;
    22→
    23→  /**
    24→   * Constructs a new NeuroSpace instance.
    25→   * @param dim - An array representing the dimensions of the space.
    26→   * @param spacing - Optional array representing the spacing of each dimension. Defaults to 1 for each dimension up to 3.
    27→   * @param origin - Optional array representing the origin of the space. Defaults to 0 for each dimension up to 3.
    28→   * @param axes - Optional AxisSet representing the orientation of the space.
    29→   * @param transform - Optional transformation matrix. If not provided, an identity matrix is used.
    30→   */
    31→  constructor(
    32→    dim: number[],
    33→    spacing?: number[],
    34→    origin?: number[],
    35→    axes?: AxisSet,
    36→    transform?: number[][]
    37→  ) {
    38→    // Check for non-positive dimensions
    39→    if (dim.some(d => d <= 0)) {
    40→      throw new Error('All dimension values must be positive');
    41→    }
    42→
    43→    this.dimValues = dim;
    44→    const D = Math.min(dim.length, 3);
    45→
    46→    // Check if spacing and origin lengths match
    47→    if (spacing && origin && spacing.length !== origin.length) {
    48→      throw new Error('Spacing and origin lengths must match');
    49→    }
    50→
    51→    // Initialize spacingValues to an array of ones
    52→    this.spacingValues = Array(D).fill(1);
    53→    if (spacing != null) {
    54→      // Check for non-positive spacing - still require positive spacing even if dimensions can be zero
    55→      if (spacing.some(s => s <= 0)) {
    56→        throw new Error('All spacing values must be positive');
    57→      }
    58→      for (let i = 0; i < Math.min(spacing.length, D); i++) {
    59→        this.spacingValues[i] = spacing[i];
    60→      }
    61→    }
    62→
    63→    // Initialize originValues to an array of zeros
    64→    this.originValues = Array(D).fill(0);
    65→    if (origin != null) {
    66→      for (let i = 0; i < Math.min(origin.length, D); i++) {
    67→        this.originValues[i] = origin[i];
    68→      }
    69→    }
    70→
    71→    if (transform) {
    72→      // Use the provided transformation matrix
    73→      this._trans = new Matrix(transform);
    74→
    75→      // Only overwrite originValues if origin is not provided
    76→      if (origin == null) {
    77→        this.originValues = [];
    78→        for (let i = 0; i < D; i++) {
    79→          this.originValues[i] = this._trans.get(i, this._trans.columns - 1);
    80→        }
    81→      }
    82→
    83→      if (axes) {
    84→        this._axes = axes;
    85→      } else {
    86→        this._axes = nearestAnatomy(this._trans);
    87→      }
    88→    } else if (axes) {
    89→      // Build the transformation matrix from axes, spacing, and origin
    90→      this._axes = axes;
    91→      this._trans = Matrix.zeros(D + 1, D + 1);
    92→      const axesArray = this._axes.axes();
    93→
    94→      // Construct the rotation-scaling part of the transformation matrix
    95→      for (let i = 0; i < D; i++) {
    96→        const dir = axesArray[i].direction;
    97→        for (let j = 0; j < D; j++) {
    98→          this._trans.set(j, i, dir[j] * this.spacingValues[i]);
    99→        }
   100→      }
   101→
   102→      // Set the translation (origin) component
   103→      for (let i = 0; i < D; i++) {
   104→        this._trans.set(i, D, this.originValues[i]);
   105→      }
   106→
   107→      // Set the bottom row for homogeneous coordinates
   108→      this._trans.set(D, D, 1);
   109→    } else {
   110→      // Neither transform nor axes provided, use default axes and identity transform
   111→      this._axes = D === 2 
   112→        ? new AxisSet2D(NamedAxis.LEFT_RIGHT, NamedAxis.POST_ANT)
   113→        : new AxisSet3D(NamedAxis.LEFT_RIGHT, NamedAxis.POST_ANT, NamedAxis.INF_SUP);
   114→
   115→      this._trans = Matrix.zeros(D + 1, D + 1);
   116→      const axesArray = this._axes.axes();
   117→
   118→      // Construct the rotation-scaling part of the transformation matrix
   119→      for (let i = 0; i < D; i++) {
   120→        const dir = axesArray[i].direction;
   121→        for (let j = 0; j < D; j++) {
   122→          this._trans.set(j, i, dir[j] * this.spacingValues[i]);
   123→        }
   124→      }
   125→
   126→      // Set the translation (origin) component
   127→      for (let i = 0; i < D; i++) {
   128→        this._trans.set(i, D, this.originValues[i]);
   129→      }
   130→
   131→      // Set the bottom row for homogeneous coordinates
   132→      this._trans.set(D, D, 1);
   133→    }
   134→
   135→    // Now, compute the inverse transformation
   136→    try {
   137→      this._inverseTrans = inverse(this._trans);
   138→    } catch (error) {
   139→      console.error('Error computing inverse transformation:', error);
   140→      console.error('Transformation matrix:', this._trans.to2DArray());
   141→      throw new Error('Failed to create NeuroSpace: transformation matrix is not invertible');
   142→    }
   143→  }
