   147→  extractSliceNeuroSpace(zlevel: number, axisToDrop?: number): NeuroSpace {
   148→    const ndim = this.ndim();
   149→    if (ndim <= 1) {
   150→      throw new Error('Cannot extract slice from a 1D space');
   151→    }
   152→  
   153→    // If axisToDrop is not specified, default to the last axis (backward compatibility)
   154→    if (axisToDrop === undefined) {
   155→      axisToDrop = ndim - 1;
   156→    }
   157→    
   158→    // Validate axisToDrop
   159→    if (axisToDrop < 0 || axisToDrop >= ndim) {
   160→      throw new Error(`axisToDrop ${axisToDrop} is out of bounds for space with ${ndim} dimensions`);
   161→    }
   162→  
   163→    // Validate zlevel
   164→    if (zlevel < 0 || zlevel >= this.dimValues[axisToDrop]) {
   165→      throw new Error(`zlevel ${zlevel} is out of bounds for axis ${axisToDrop}`);
   166→    }
   167→  
   168→    // Update dimension arrays by removing the dropped axis
   169→    const newDim = [...this.dimValues.slice(0, axisToDrop), ...this.dimValues.slice(axisToDrop + 1)];
   170→    const newSpacing = [...this.spacingValues.slice(0, axisToDrop), ...this.spacingValues.slice(axisToDrop + 1)];
   171→    const newOrigin = [...this.originValues.slice(0, axisToDrop), ...this.originValues.slice(axisToDrop + 1)];
   172→  
   173→    // Remove the axis corresponding to the dropped dimension
   174→    const axesArray = this._axes.axes();
   175→    const newAxesArray = [...axesArray.slice(0, axisToDrop), ...axesArray.slice(axisToDrop + 1)];
   176→  
   177→    // Create a new AxisSet based on the remaining axes
   178→    let newAxes: AxisSet;
   179→    if (newAxesArray.length === 2) {
   180→      newAxes = new AxisSet2D(newAxesArray[0], newAxesArray[1]);
   181→    } else if (newAxesArray.length === 1) {
   182→      newAxes = new AxisSet1D(newAxesArray[0]);
   183→    } else {
   184→      throw new Error('Unsupported number of axes after dropping dimension');
   185→    }
   186→  
   187→    // Construct the transformation matrix based on remaining dimensions
   188→    const D = newAxesArray.length;
   189→    const newTrans = Matrix.zeros(D + 1, D + 1);
   190→  
   191→    // Build the rotation-scaling part of the transformation matrix
   192→    for (let i = 0; i < D; i++) {
   193→      const dir = newAxesArray[i].direction;
   194→      // Only use the first D components of the direction vector
   195→      // since we're creating a DxD matrix (2x2 for 2D space)
   196→      for (let j = 0; j < D; j++) {
   197→        newTrans.set(j, i, dir[j] * newSpacing[i]);
   198→      }
   199→    }
   200→  
   201→    // Set the translation (origin) component
   202→    for (let i = 0; i < D; i++) {
   203→      newTrans.set(i, D, newOrigin[i]);
   204→    }
   205→  
   206→    // Set the bottom row for homogeneous coordinates
   207→    newTrans.set(D, D, 1);
   208→  
   209→    // Debug: Check if transformation matrix might be singular
   210→    const transArray = newTrans.to2DArray();
   211→    
   212→    // Check if the transformation matrix is singular
   213→    let detValue = 0;
   214→    if (D === 2) {
   215→      detValue = transArray[0][0] * transArray[1][1] - transArray[0][1] * transArray[1][0];
   216→    } else if (D === 1) {
   217→      detValue = transArray[0][0];
   218→    }
   219→    
   220→    if (Math.abs(detValue) < 1e-10) {
   221→      console.error('extractSliceNeuroSpace - Singular transformation matrix detected!');
   222→      console.error('- Dimensions:', newDim);
   223→      console.error('- Spacing:', newSpacing);
   224→      console.error('- Origin:', newOrigin);
   225→      console.error('- Axes:', newAxes.toString());
   226→      console.error('- Transformation matrix:', transArray);
   227→      console.error('- Determinant:', detValue);
   228→      
   229→      // Create a simple identity-based transformation as fallback
   230→      const fallbackTrans = Matrix.zeros(D + 1, D + 1);
   231→      for (let i = 0; i < D; i++) {
   232→        fallbackTrans.set(i, i, newSpacing[i]);
   233→        fallbackTrans.set(i, D, newOrigin[i]);
   234→      }
   235→      fallbackTrans.set(D, D, 1);
   236→      
   237→      console.log('Using fallback transformation matrix:', fallbackTrans.to2DArray());
   238→      return new NeuroSpace(newDim, newSpacing, newOrigin, newAxes, fallbackTrans.to2DArray());
   239→    }
   240→    
   241→    // Create and return the new 2D NeuroSpace
   242→    return new NeuroSpace(newDim, newSpacing, newOrigin, newAxes, transArray);
   243→  }
