   245→
   246→  dropDim(): NeuroSpace | null {
   247→    const ndim = this.ndim();
   248→    if (ndim <= 1) {
   249→      return null;
   250→    }
   251→
   252→
   253→    // Create new arrays for dim, spacing, and origin, dropping the last element
   254→    const newDim = this.dim.slice(0, -1);
   255→    const newSpacing = this.spacing.slice(0, -1);
   256→    const newOrigin = this.origin.slice(0, -1);
   257→
   258→    // For AxisSet, we'll keep the first n-1 dimensions
   259→    let newAxes: AxisSet;
   260→    if (ndim > 3) {
   261→      newAxes = this.axes;
   262→    } else {
   263→      newAxes = this.axes.dropDim() as AxisSet;
   264→    }
   265→
   266→    // For the transformation matrix, we need to create a proper homogeneous matrix
   267→    const newNdim = newDim.length;
   268→    const newTrans = Matrix.zeros(newNdim + 1, newNdim + 1);
   269→    
   270→    // For 3D to 2D reduction, we need special handling
   271→    if (newNdim === 2 && ndim === 3) {
   272→      // Get the axes that will be kept (first two axes from AxisSet3D.dropDim())
   273→      const axesArray = this._axes.axes();
   274→      const axis1 = axesArray[0];
   275→      const axis2 = axesArray[1];
   276→      const axis3 = axesArray[2]; // The axis being dropped
   277→      
   278→      // Get the transformation matrix columns for each axis (including spacing)
   279→      const col1 = [
   280→        this._trans.get(0, 0), // x component of first axis
   281→        this._trans.get(1, 0), // y component of first axis
   282→        this._trans.get(2, 0)  // z component of first axis
   283→      ];
   284→      
   285→      const col2 = [
   286→        this._trans.get(0, 1), // x component of second axis
   287→        this._trans.get(1, 1), // y component of second axis
   288→        this._trans.get(2, 1)  // z component of second axis
   289→      ];
   290→      
   291→      // Check if the first two columns, when projected to 2D, would create a singular matrix
   292→      // This happens when both columns point primarily in the Z direction
   293→      const col1Magnitude2D = Math.sqrt(col1[0] * col1[0] + col1[1] * col1[1]);
   294→      const col2Magnitude2D = Math.sqrt(col2[0] * col2[0] + col2[1] * col2[1]);
   295→      
   296→      // Check if either column has negligible XY components
   297→      if (col1Magnitude2D < 1e-10 || col2Magnitude2D < 1e-10) {
   298→        // At least one axis points primarily in Z direction
   299→        // This will create a singular 2x2 matrix
   300→        
   301→        // Strategy: Create a valid 2D transformation that preserves as much structure as possible
   302→        // We'll create an orthonormal 2D basis that best represents the data
   303→        
   304→        // If col1 has no XY component, use a default [1,0] direction
   305→        let newCol1: number[];
   306→        if (col1Magnitude2D < 1e-10) {
   307→          newCol1 = [this.spacingValues[0], 0];
   308→        } else {
   309→          // Normalize the XY components and scale by original spacing
   310→          const scale = Math.sqrt(col1[0] * col1[0] + col1[1] * col1[1] + col1[2] * col1[2]);
   311→          newCol1 = [
   312→            col1[0] * scale / col1Magnitude2D,
   313→            col1[1] * scale / col1Magnitude2D
   314→          ];
   315→        }
   316→        
   317→        // For col2, ensure it's orthogonal to newCol1
   318→        let newCol2: number[];
   319→        if (col2Magnitude2D < 1e-10) {
   320→          // Use perpendicular to newCol1
   321→          newCol2 = [-newCol1[1] * this.spacingValues[1] / this.spacingValues[0], newCol1[0] * this.spacingValues[1] / this.spacingValues[0]];
   322→        } else {
   323→          // Project col2 onto plane and make orthogonal to newCol1
   324→          const scale = Math.sqrt(col2[0] * col2[0] + col2[1] * col2[1] + col2[2] * col2[2]);
   325→          const proj2 = [col2[0], col2[1]];
   326→          
   327→          // Gram-Schmidt orthogonalization
   328→          const dot = (proj2[0] * newCol1[0] + proj2[1] * newCol1[1]) / (newCol1[0] * newCol1[0] + newCol1[1] * newCol1[1]);
   329→          newCol2 = [
   330→            (proj2[0] - dot * newCol1[0]) * scale / col2Magnitude2D,
   331→            (proj2[1] - dot * newCol1[1]) * scale / col2Magnitude2D
   332→          ];
   333→          
   334→          // Check if newCol2 is zero (parallel case)
   335→          const newCol2Mag = Math.sqrt(newCol2[0] * newCol2[0] + newCol2[1] * newCol2[1]);
   336→          if (newCol2Mag < 1e-10) {
   337→            // Use perpendicular
   338→            newCol2 = [-newCol1[1], newCol1[0]];
   339→          }
   340→        }
   341→        
   342→        // Set the transformation matrix
   343→        newTrans.set(0, 0, newCol1[0]);
   344→        newTrans.set(1, 0, newCol1[1]);
   345→        newTrans.set(0, 1, newCol2[0]);
   346→        newTrans.set(1, 1, newCol2[1]);
   347→      } else {
   348→        // Normal case: just copy the first 2x2 submatrix
   349→        for (let i = 0; i < 2; i++) {
   350→          for (let j = 0; j < 2; j++) {
   351→            newTrans.set(i, j, this._trans.get(i, j));
   352→          }
   353→        }
   354→      }
   355→    } else {
   356→      // General case: copy the appropriate submatrix
   357→      for (let i = 0; i < newNdim; i++) {
   358→        for (let j = 0; j < newNdim; j++) {
   359→          newTrans.set(i, j, this._trans.get(i, j));
   360→        }
   361→      }
   362→    }
   363→    
   364→    // Copy the translation part (origin)
   365→    for (let i = 0; i < newNdim; i++) {
   366→      newTrans.set(i, newNdim, this._trans.get(i, this.ndim()));
   367→    }
   368→    
   369→    // Set the homogeneous coordinate
   370→    newTrans.set(newNdim, newNdim, 1);
   371→
   372→    // Create a new NeuroSpace with the updated properties
   373→    return new NeuroSpace(
   374→      newDim,
   375→      newSpacing,
   376→      newOrigin,
   377→      newAxes,
   378→      newTrans.to2DArray()
   379→    );
   380→  }
