   385→  /**
   386→   * Gets the number of dimensions.
   387→   * @returns The number of dimensions.
   388→   */
   389→  ndim(): number {
   390→    return this.dim.length;
   391→  }
   392→
   393→  /**
   394→   * Calculates the centroid of the NeuroSpace.
   395→   * The centroid is the geometric center of the space, calculated by averaging
   396→   * the coordinates of two opposite corners of the bounding box.
   397→   * 
   398→   * @returns An array representing the coordinates of the centroid.
   399→   */
   400→  centroid(): number[] {
   401→    const [c1, c2] = this.bounds();
   402→    //console.log(c1, c2);
   403→    const ndim = Math.min(this.ndim(), 3);
   404→    const centroid = c1.slice(0, ndim).map((coord, i) => (coord + c2[i]) / 2);
   405→    //console.log(centroid);
   406→    return centroid;
   407→  }
