   409→  /**
   410→   * Gets the size of a specific dimension based on the axis.
   411→   * @param axis - The axis for which to get the dimension size.
   412→   * @returns The size of the dimension.
   413→   */
   414→  dimOf(axis: NamedAxis): number {
   415→    const dir = axis.direction.map(Math.abs);
   416→    const dnum = this.whichDim(axis);
   417→    return this.dim[dnum];
   418→  }
   419→
   420→  /**
   421→   * Determines which dimension corresponds to the given axis.
   422→   * @param axis - The axis to match.
   423→   * @returns The index of the matching dimension.
   424→   * @throws Error if no matching axis is found.
   425→   */
   426→  whichDim(axis: NamedAxis): number {
   427→    const axes = this._axes.axes();
   428→    const index = axes.findIndex(a => a.axis === axis.axis || a.axis === oppositeAxis(axis).axis);
   429→    if (index === -1) {
   430→      throw new Error(`Cannot find matching axis of: ${axis.axis}`);
   431→    }
   432→    return index;
   433→  }
