   472→  /**
   473→   * Calculates the bounds of the NeuroSpace.
   474→   * @returns A tuple containing the minimum and maximum coordinates.
   475→   */
   476→  bounds(): [number[], number[]] {
   477→    const d = Math.min(3, this.ndim());
   478→    const zeroGrid = Array(d).fill(0);
   479→    const maxGrid = this.dim.slice(0, d).map(d => d - 1);
   480→    const c1 = this.gridToCoord(zeroGrid); 
   481→    const c2 = this.gridToCoord(maxGrid);
   482→    return [c1, c2];
   483→  }
