   487→  /**
   488→   * Converts a linear index to grid coordinates.
   489→   * @param idx - The linear index.
   490→   * @returns An array representing grid coordinates.
   491→   */
   492→  indexToGrid(idx: number): number[] {
   493→    return indexToGrid(idx, this.dim);
   494→  }
   495→
   496→  /**
   497→   * Converts a linear index to real-world coordinates.
   498→   * @param idx - The linear index.
   499→   * @returns An array representing real-world coordinates.
   500→   */
   501→  indexToCoord(idx: number): number[] {
   502→    const d = Math.min(3, this.ndim());
   503→    const grid = this.indexToGrid(idx);
   504→    const extendedGrid = [...grid.slice(0, d), 1];
   505→    const res = this.trans.mmul(Matrix.columnVector(extendedGrid));
   506→    return res.getColumn(0).slice(0, d);
   507→  }
   508→
   509→  /**
   510→   * Converts real-world coordinates to a linear index.
   511→   * @param coords - An array of real-world coordinates.
   512→   * @returns The corresponding linear index.
   513→   */
   514→  coordToIndex(coords: number[]): number {
   515→    const grid = this._inverseTrans.mmul(Matrix.columnVector([...coords, 1])).to1DArray();
   516→    return gridToIndex(this.dim, grid.slice(0, this.ndim()));
   517→  }
   518→
   519→  /**
   520→   * Converts real-world coordinates to grid coordinates.
   521→   * @param coords - An array of real-world coordinates.
   522→   * @returns An array representing grid coordinates.
   523→   */
   524→  coordToGrid(coords: number[]): number[] {
   525→    const grid = this._inverseTrans.mmul(Matrix.columnVector([...coords, 1])).to1DArray();
   526→    return grid.slice(0, this.ndim());
   527→  }
   528→
   529→  containsCoord(coords: number[]): boolean {
   530→    const grid = this.coordToGrid(coords);
   531→    return grid.every((g, i) => g >= 0 && g < this.dim[i]);
   532→  }
