   534→  /**
   535→   * Converts voxel coordinates to world coordinates.
   536→   * Alias for gridToCoord.
   537→   * @param voxel - An array of voxel coordinates.
   538→   * @returns An array representing world coordinates.
   539→   */
   540→  voxelToWorld(voxel: number[]): number[] {
   541→    return this.gridToCoord(voxel);
   542→  }
