   544→  /**
   545→   * Converts world coordinates to voxel coordinates.
   546→   * Alias for coordToGrid.
   547→   * @param world - An array of world coordinates.
   548→   * @returns An array representing voxel coordinates.
   549→   */
   550→  worldToVoxel(world: number[]): number[] {
   551→    return this.coordToGrid(world);
   552→  }
   553→
   554→  /**
   555→   * Converts voxel coordinates to real-world coordinates.
   556→   * @param vox - An array of voxel coordinates.
   557→   * @returns An array representing real-world coordinates.
   558→   */
   559→  gridToGrid(vox: number[]): number[] {
   560→    const nd = this.ndim();
   561→    const tx = this._inverseTrans.subMatrix(0, nd - 1, 0, nd - 1);
   562→    const idx: [number, number][] = tx
   563→      .to2DArray()
   564→      .flatMap((row, i) =>
   565→        row.map((v, j) => (v !== 0 ? ([i, j] as [number, number]) : null))
   566→      )
   567→      .filter((v): v is [number, number] => v !== null);
   568→
   569→    idx.forEach(([i, j]) => tx.set(i, j, Math.sign(tx.get(i, j))));
   570→    const ovox = tx.mmul(Matrix.columnVector(vox));
   571→    const offset = tx
   572→      .to2DArray()
   573→      .map((row) => (row.some((v) => v < 0) ? this.dim[row.indexOf(-1)] : 0));
   574→    return ovox.to1DArray().map((v, i) => v + offset[i]);
