   582→  gridToCoord(coords: number[]): number[] {
   583→    const requiredSize = this.trans.rows;
   584→    const paddingSize = requiredSize - coords.length - 1; // Subtracting 1 for the homogeneous coordinate
   585→    if (paddingSize < 0) {
   586→      throw new Error('Too many coordinates provided for gridToCoord.');
   587→    }
   588→    const extendedCoords = [...coords, ...Array(paddingSize).fill(0), 1];
   589→    const ret = this.trans.mmul(Matrix.columnVector(extendedCoords)).to1DArray();
   590→    const md = Math.min(this.ndim(), 3);
   591→    return ret.slice(0, md);
   592→  }
