   604→  reorient(orient: AxisSet): NeuroSpace {
   605→  
   606→    const ndim = this.ndim();
   607→    if (ndim !== 2 && ndim !== 3) {
   608→      throw new Error(`Reorientation is only supported for 2D and 3D spaces. Got ${ndim}D space.`);
   609→    }
   610→  
   611→    let anat: AxisSet;
   612→    try {
   613→      anat = ndim === 2
   614→        ? findAnatomy2D(orient.axes()[0].name, orient.axes()[1].name)
   615→        : findAnatomy3D(orient.axes()[0].name, orient.axes()[1].name, orient.axes()[2].name);
   616→    } catch (error) {
   617→      const errorMessage = error instanceof Error ? error.message : String(error);
   618→      throw new Error(`Failed to find matching anatomy: ${errorMessage}`);
   619→    }
   620→  
   621→    // Compute permutation mapping
   622→    const { perm, flip } = this.computeAxisPermutation(this.axes.axes(), anat.axes());
   623→  
   624→    // Reorder dim and spacing according to the permutation
   625→    const newDim = perm.map((p) => this.dim[p]);
   626→    const newSpacing = perm.map((p) => this.spacing[p]);
   627→  
   628→    // Calculate the new origin
   629→    // We need to transform the corners of the original space to maintain the same physical bounds
   630→    const newOrigin = new Array(ndim).fill(0);
   631→    
   632→    // For each axis in the new orientation
   633→    for (let i = 0; i < ndim; i++) {
   634→      const sourceAxisIndex = perm[i];
   635→      
   636→      if (flip[i] === -1) {
   637→        // If the axis is flipped, the origin needs to be adjusted
   638→        // to maintain the same physical bounds
   639→        // The new origin is at the opposite end of the dimension
   640→        newOrigin[i] = this.origin[sourceAxisIndex] + (this.dim[sourceAxisIndex] - 1) * this.spacing[sourceAxisIndex];
   641→      } else {
   642→        // If not flipped, keep the same origin value
   643→        newOrigin[i] = this.origin[sourceAxisIndex];
   644→      }
   645→    }
   646→  
   647→    // Create a new transformation matrix
   648→    const newTrans = Matrix.zeros(ndim + 1, ndim + 1);
   649→    
   650→    // Set the homogeneous coordinate
   651→    newTrans.set(ndim, ndim, 1);
   652→    
   653→    // Build the rotation-scaling part of the transformation matrix
   654→    const anatAxes = anat.axes();
   655→    for (let i = 0; i < ndim; i++) {
   656→      const dir = anatAxes[i].direction;
   657→      for (let j = 0; j < ndim; j++) {
   658→        newTrans.set(j, i, dir[j] * newSpacing[i]);
   659→      }
   660→    }
   661→    
   662→    // Set the translation component
   663→    for (let i = 0; i < ndim; i++) {
   664→      newTrans.set(i, ndim, newOrigin[i]);
   665→    }
   666→  
   667→    
   668→    // Create and return the new NeuroSpace with the updated properties
   669→    const newSpace = new NeuroSpace(
   670→      newDim,
   671→      newSpacing,
   672→      newOrigin,
   673→      anat,
   674→      newTrans.to2DArray()
   675→    );
   676→    
   677→    // Verify the bounds are preserved after reorientation
   678→    const [origMin, origMax] = this.bounds();
   679→    const [newMin, newMax] = newSpace.bounds();
   680→    
   681→    return newSpace;
   682→  }
