   687→  // Helper function to compute axis permutation and flips
   688→computeAxisPermutation(oldAxes: NamedAxis[], newAxes: NamedAxis[]): { perm: number[], flip: number[] } {
   689→    const ndim = oldAxes.length;
   690→    const perm = new Array(ndim);
   691→    const flip = new Array(ndim);
   692→  
   693→    for (let i = 0; i < ndim; i++) {
   694→      const newAxis = newAxes[i];
   695→      let found = false;
   696→      for (let j = 0; j < ndim; j++) {
   697→        const oldAxis = oldAxes[j];
   698→        if (newAxis.name === oldAxis.name) {
   699→          perm[i] = j;
   700→          flip[i] = 1;
   701→          found = true;
   702→          break;
   703→        } else if (newAxis.name === oppositeAxis(oldAxis).name) {
   704→          perm[i] = j;
   705→          flip[i] = -1;
   706→          found = true;
   707→          break;
   708→        }
   709→      }
   710→      if (!found) {
   711→        throw new Error(`Cannot find matching axis for ${newAxis.name}`);
   712→      }
   713→    }
   714→    return { perm, flip };
   715→  }
