   717→  permuteGridCoordinates(coords: number[], axes: AxisSet): number[] {
   718→    //console.log("converting coords ... ", coords);
   719→    //console.log("to axes ... ", axes);
   720→    const permMatrix = this.getPermutationMatrixTo(axes);
   721→    //console.log("permMatrix ... ", permMatrix);
   722→    const cvec = Matrix.columnVector([...coords, 1]);
   723→    //console.log("cvec ... ", cvec);
   724→    const result = permMatrix.mmul(cvec).to1DArray();
   725→    //console.log("result ... ", result);
   726→    return result.slice(0, this.ndim());
   727→  }
