   729→  /**
   730→   * Calculates the bounds of the NeuroSpace with respect to a given set of axes.
   731→   * @param axes - The AxisSet defining the desired orientation.
   732→   * @returns A tuple containing the minimum and maximum coordinates in the local coordinate space.
   733→   */
   734→  boundsFromView(axes: AxisSet): [number[], number[]] {
   735→    const ndim = Math.min(this.ndim(), 3); // Limit to 3D space
   736→    const dims = this.dim.slice(0, ndim);
   737→
   738→    // Generate all corner indices in grid space
   739→    const cornerIndices = this.generateCornerIndices(dims);
   740→
   741→    // Convert grid corners to world coordinates
   742→    const worldCorners = cornerIndices.map((gridCoord) => this.gridToCoord(gridCoord));
   743→
   744→    // Transform world coordinates to the local coordinate space of the provided axes
   745→    const transformedCorners = worldCorners.map((coord) =>
   746→      this.transformCoordToAxes(coord, axes)
   747→    );
   748→
   749→    // Initialize min and max bounds
   750→    const minBounds = Array(ndim).fill(Infinity);
   751→    const maxBounds = Array(ndim).fill(-Infinity);
   752→
   753→    // Determine the min and max bounds along each axis
   754→    for (const corner of transformedCorners) {
   755→      for (let i = 0; i < ndim; i++) {
   756→        if (corner[i] < minBounds[i]) minBounds[i] = corner[i];
   757→        if (corner[i] > maxBounds[i]) maxBounds[i] = corner[i];
   758→      }
   759→    }
   760→
   761→    return [minBounds, maxBounds];
   762→  }
   763→
   764→  /**
   765→   * Generates all corner indices for an n-dimensional grid.
   766→   * @param dims - The dimensions of the grid.
   767→   * @returns An array of grid coordinates representing each corner.
   768→   */
   769→  generateCornerIndices(dims: number[]): number[][] {
   770→    const ndim = dims.length;
   771→    const numCorners = 2 ** ndim;
   772→    const corners: number[][] = [];
   773→
   774→    for (let i = 0; i < numCorners; i++) {
   775→      const corner: number[] = [];
   776→      for (let j = 0; j < ndim; j++) {
   777→        // If the j-th bit of i is set, use the max index for that dimension
   778→        const index = (i >> j) & 1 ? dims[j] - 1 : 0;
   779→        corner.push(index);
   780→      }
   781→      corners.push(corner);
   782→    }
   783→
   784→    return corners;
   785→  }
   786→
   787→  /**
   788→   * Transforms a coordinate from world space to the local coordinate space defined by the given axes.
   789→   * @param coord - The coordinate in world space.
   790→   * @param axes - The AxisSet defining the desired orientation.
   791→   * @returns The coordinate in the local coordinate space.
   792→   */
   793→  transformCoordToAxes(coord: number[], axes: AxisSet): number[] {
   794→    const ndim = Math.min(this.ndim(), 3); // Limit to 3D
   795→    const sourceAxes = this._axes.axes();
   796→    const targetAxes = axes.axes();
   797→
   798→    // Build the rotation matrix to align source axes with target axes
   799→    const rotationMatrix = Matrix.zeros(ndim, ndim);
   800→
   801→    for (let i = 0; i < ndim; i++) {
   802→      const targetAxis = targetAxes[i];
   803→
   804→      // Find corresponding source axis
   805→      let found = false;
   806→      for (let j = 0; j < ndim; j++) {
   807→        const sourceAxis = sourceAxes[j];
   808→        if (targetAxis.name === sourceAxis.name) {
   809→          // Direct match
   810→          rotationMatrix.set(i, j, 1);
   811→          found = true;
   812→          break;
   813→        } else if (targetAxis.name === oppositeAxis(sourceAxis).name) {
   814→          // Opposite axis
   815→          rotationMatrix.set(i, j, -1);
   816→          found = true;
   817→          break;
   818→        }
   819→      }
   820→
   821→      if (!found) {
   822→        throw new Error(`Axis ${targetAxis.name} does not have a matching source axis.`);
   823→      }
   824→    }
   825→
   826→    const coordMatrix = Matrix.columnVector(coord.slice(0, ndim));
   827→    const transformedCoord = rotationMatrix.mmul(coordMatrix).getColumn(0);
   828→
   829→    return transformedCoord;
   830→  }
