   837→  /**
   838→   * Generates a sequence of values along a given axis within the space.
   839→   * @param axis - The axis along which to generate the sequence.
   840→   * @param step - The step size between values in the sequence.
   841→   * @returns An array of numbers representing the sequence along the axis.
   842→   * @throws Error if the provided axis doesn't match any axis in the space.
   843→   */
   844→  seqAlong(axis: NamedAxis, step: number): number[] {
   845→    //console.log('step', step);
   846→    const matchedAxisIndex = this.findMatchingAxis(axis);
   847→    //console.log('matchedAxisIndex', matchedAxisIndex);
   848→    if (matchedAxisIndex === null) {
   849→      throw new Error('The provided axis does not match any axis in the space.');
   850→    }
   851→
   852→    const [start, end] = this.bounds().map((bound) => bound[matchedAxisIndex]);
   853→    //console.log('start, end', start, end);
   854→    const axes = this._axes.axes();
   855→    const direction = axes[matchedAxisIndex].direction[matchedAxisIndex];
   856→    //console.log(direction);
   857→    //console.log(start, end);
   858→    if (direction > 0) {
   859→      return this.generateSequence(start, end, step);
   860→    } else {
   861→      return this.generateSequence(end, start, -step);
   862→    }
   863→  }
   864→
   865→  /**
   866→   * Returns an array of slice indices along a given axis.
   867→   * @param axis - The axis along which to generate slice indices.
   868→   * @returns An array of numbers representing the slice indices from 0 to ndom-1.
   869→   * @throws Error if the provided axis doesn't match any axis in the space.
   870→   */
   871→  sliceIndices(axis: NamedAxis): number[] {
   872→    const matchedAxisIndex = this.findMatchingAxis(axis);
   873→    if (matchedAxisIndex === null) {
   874→      throw new Error('The provided axis does not match any axis in the space.');
   875→    }
   876→
   877→    const d = this.dim[matchedAxisIndex];
   878→    return Array.from({ length: d }, (_, i) => i);
   879→  }
