   881→  /**
   882→   * Finds the index of a matching axis in the space.
   883→   * @param axis - The axis to match.
   884→   * @param ignoreDirection - Whether to ignore the direction when matching. Defaults to false.
   885→   * @returns The index of the matching axis, or null if no match is found.
   886→   */
   887→  private findMatchingAxis(axis: NamedAxis, ignoreDirection: boolean = false): number | null {
   888→    const axes = this._axes.axes();
   889→    for (let i = 0; i < axes.length; i++) {
   890→      if (
   891→        ignoreDirection
   892→          ? axes[i].axis === axis.axis
   893→          : axes[i].axis === axis.axis || axes[i].axis === oppositeAxis(axis).axis
   894→      ) {
   895→        return i;
   896→      }
   897→    }
   898→    return null;
   899→  }
