   901→  /**
   902→   * Generates a sequence of numbers.
   903→   * @param start - The starting value of the sequence.
   904→   * @param end - The ending value of the sequence.
   905→   * @param step - The step size between values.
   906→   * @returns An array of numbers representing the sequence.
   907→   */
   908→  private generateSequence(start: number, end: number, step: number): number[] {
   909→    //console.log('start, end, step', start, end, step);
   910→    const sequence: number[] = [];
   911→    if (step > 0) {
   912→      for (let value = start; value <= end; value += step) {
   913→        sequence.push(value);            
   914→      }
   915→    } else {
   916→      for (let value = start; value >= end; value += step) {
   917→        sequence.push(value);
   918→      }
   919→    }
   920→    return sequence;
   921→  }
