   991→  /**
   992→   * Generates a transformation matrix to convert real-world coordinates from this space to another space.
   993→   * @param targetSpace - The target NeuroSpace to convert coordinates to.
   994→   * @returns A transformation matrix that converts real-world coordinates from this space to the target space.
   995→   */
   996→  getTransformationMatrixTo(targetSpace: NeuroSpace): Matrix {
   997→    // Compute the transformation matrix from this space to the target space
   998→    // M = T_target * inv(T_source)
   999→    const invSourceTrans = this._inverseTrans;
  1000→    const targetTrans = targetSpace.getTrans();
  1001→    const transformationMatrix = targetTrans.mmul(invSourceTrans);
  1002→    return transformationMatrix;
  1003→  }
