  1005→  /**
  1006→   * Generates a transformation matrix to convert voxel coordinates from this space to another compatible space.
  1007→   * @param targetAxes - The target NeuroSpace to convert coordinates to.
  1008→   * @returns A transformation matrix that converts voxel coordinates from this space to the target space.
  1009→   * @throws Error if the spaces are not compatible.
  1010→   */
  1011→  getPermutationMatrixTo(targetAxes: AxisSet): Matrix {
  1012→    if (!this.isCompatibleWithAxes(targetAxes)) {
  1013→      throw new Error('The axes are not compatible for transformation.');
  1014→    }
  1015→
  1016→    const sourceAxes = this._axes.axes();
  1017→    const targetAxesArray = targetAxes.axes();
  1018→    const n = Math.min(this.ndim(), targetAxesArray.length, 3);
  1019→
  1020→    // Initialize the transformation matrix
  1021→    const transformMatrix = Matrix.zeros(n + 1, n + 1);
  1022→    transformMatrix.set(n, n, 1); // Homogeneous coordinate
  1023→
  1024→    for (let i = 0; i < n; i++) {
  1025→      const targetAxis = targetAxesArray[i];
  1026→
  1027→      // Find corresponding source axis
  1028→      let found = false;
  1029→      for (let j = 0; j < n; j++) {
  1030→        const sourceAxis = sourceAxes[j];
  1031→        if (targetAxis.name === sourceAxis.name) {
  1032→          // Direct match
  1033→          transformMatrix.set(i, j, 1);
  1034→          found = true;
  1035→          break;
  1036→        } else if (targetAxis.name === oppositeAxis(sourceAxis).name) {
  1037→          // Opposite axis
  1038→          transformMatrix.set(i, j, -1);
  1039→          // Adjust translation component for reflection
  1040→          transformMatrix.set(i, n, this.dim[j] - 1);
  1041→          found = true;
  1042→          break;
  1043→        }
  1044→      }
  1045→
  1046→      if (!found) {
  1047→        throw new Error(`Axis ${targetAxis.name} does not have a matching source axis.`);
  1048→      }
  1049→    }
  1050→
  1051→    return transformMatrix;
  1052→  }
