            margin-bottom: 10px;
        }

        .subtitle {
            text-align: center;
            color: #888;
            margin-bottom: 30px;
        }

        .coordinate-section {
            margin-bottom: 50px;
            background-color: #2a2a2a;
            border-radius: 10px;
            padding: 20px;
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.3);
        }

        .coordinate-header {
            background-color: #3a3a3a;
            margin: -20px -20px 20px -20px;
            padding: 15px 20px;
            border-radius: 10px 10px 0 0;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .coordinate-title {
            font-size: 20px;
            color: #FFC107;
            margin: 0;
        }

        .coordinate-values {
            font-family: 'Courier New', monospace;
            color: #4CAF50;
            font-size: 16px;
        }

        .slices-container {
            display: grid;
            grid-template-columns: repeat(3, 1fr);
            gap: 20px;
            max-width: 1600px;
            margin: 0 auto;
        }

        .slice-box {
            text-align: center;
            background-color: #1a1a1a;
            border-radius: 8px;
            padding: 15px;
            transition: transform 0.2s;
        }

        .slice-box:hover {
            transform: scale(1.02);
            background-color: #252525;
        }

        .slice-box h3 {
            margin: 0 0 10px 0;
            color: #64B5F6;
            font-size: 18px;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        .slice-box img {
            width: 100%;
            height: auto;
            border: 2px solid #444;
            border-radius: 4px;
            cursor: zoom-in;
        }

        .slice-box img.zoomed {
            cursor: zoom-out;
        }

        .legend {
            background-color: #2a2a2a;
            padding: 20px;
            border-radius: 10px;
            margin-bottom: 30px;
            text-align: center;
        }

        .legend h2 {
            color: #4CAF50;
            margin-top: 0;
        }

        .legend-item {
            display: inline-block;
            margin: 0 20px;
            color: #ccc;
        }

        .crosshair-demo {
            display: inline-block;
            width: 30px;
            height: 30px;
            position: relative;
            vertical-align: middle;
            margin-right: 10px;
        }

        .crosshair-demo::before,
        .crosshair-demo::after {
            content: '';
            position: absolute;
            background-color: #FF0000;
        }

        .crosshair-demo::before {
            width: 100%;
            height: 2px;
            top: 50%;
            left: 0;
            transform: translateY(-50%);
        }

        .crosshair-demo::after {
            width: 2px;
            height: 100%;
            top: 0;
            left: 50%;
            transform: translateX(-50%);
        }

        .modal {
            display: none;
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background-color: rgba(0, 0, 0, 0.9);
            z-index: 1000;
            cursor: zoom-out;
        }

        .modal img {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            max-width: 90%;
            max-height: 90%;
            border: 3px solid #fff;
        }

        .info {
            background-color: #2a2a2a;
            padding: 20px;
            border-radius: 10px;
            margin-bottom: 30px;
        }

        .info p {
            margin: 5px 0;
            color: #ccc;
        }
    </style>
</head>
<body>
    <h1>Orthogonal Slice Visualization</h1>
    <p class="subtitle">MNI152 Nonlinear Asymmetric Template</p>

    <div class="info">
        <h2>Visualization Information</h2>
        <p><strong>Template:</strong> MNI152NLin2009aAsym (1mm resolution T1-weighted)</p>
        <p><strong>Crosshairs:</strong> Red lines marking the world coordinate position</p>
        <p><strong>Orientation Labels:</strong> Yellow letters indicating anatomical directions</p>
        <p><strong>Views:</strong> Axial (transverse), Sagittal, and Coronal planes</p>
