 * Draw a slice to canvas with crosshairs
 */
function drawSliceWithCrosshairs(
  sliceData: Float32Array | Float64Array,
  width: number,
  height: number,
  crosshairX: number,
  crosshairY: number,
  label: string
): Buffer {
  const canvas = createCanvas(width, height);
  const ctx = canvas.getContext('2d');

  // Find min/max for normalization
  let min = Infinity;
  let max = -Infinity;
  for (let i = 0; i < sliceData.length; i++) {
    const val = sliceData[i];
    if (val < min) min = val;
    if (val > max) max = val;
  }

  // Create image data
  const imageData = ctx.createImageData(width, height);
  const data = imageData.data;

  // Fill with normalized grayscale values
  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const idx = y * width + x;
      const val = sliceData[idx];
      const normalized = Math.floor(((val - min) / (max - min)) * 255);

      const pixelIdx = idx * 4;
      data[pixelIdx] = normalized;     // R
      data[pixelIdx + 1] = normalized; // G
      data[pixelIdx + 2] = normalized; // B
      data[pixelIdx + 3] = 255;       // A
    }
  }

  ctx.putImageData(imageData, 0, 0);

  // Draw crosshairs
  ctx.strokeStyle = 'red';
  ctx.lineWidth = 2;

  // Vertical line
  ctx.beginPath();
  ctx.moveTo(crosshairX, 0);
  ctx.lineTo(crosshairX, height);
  ctx.stroke();

  // Horizontal line
  ctx.beginPath();
  ctx.moveTo(0, crosshairY);
  ctx.lineTo(width, crosshairY);
  ctx.stroke();

  // Draw label
  ctx.fillStyle = 'yellow';
  ctx.font = '16px Arial';
  ctx.fillText(label, 10, 20);

  return canvas.toBuffer('image/png');
}

