    fs.writeFileSync(path.join(outputDir, 'index.html'), html);
    console.log(`\n✅ HTML viewer created: ${path.join(outputDir, 'index.html')}`);
    console.log('\nAll slices extracted and saved successfully!');

  } catch (error) {
    console.error('Error:', error);
