  // Check if we got valid data
  if (!imageData || imageData.length === 0) {
    console.warn('Backend returned empty image data');
    // Return a 1x1 transparent image as fallback
    const canvas = new OffscreenCanvas(1, 1);
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, 1, 1);
    }
    return createImageBitmap(canvas);
  }

  // Log the size of the returned data
  console.log(`Received image data: ${imageData.length} bytes`);

  // Check PNG signature (89 50 4E 47 0D 0A 1A 0A)
  const pngSignature = [0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A];
  const first8Bytes = Array.from(imageData.slice(0, 8));
  const isPNG = pngSignature.every((byte, i) => byte === first8Bytes[i]);

  if (!isPNG) {
    console.error('Data is not a valid PNG file!');
    console.log('Expected PNG signature:', pngSignature.map(b => b.toString(16).padStart(2, '0')).join(' '));
    console.log('Actual first 8 bytes:', first8Bytes.map(b => b.toString(16).padStart(2, '0')).join(' '));
    console.log('First 32 bytes:', Array.from(imageData.slice(0, 32)).map(b => b.toString(16).padStart(2, '0')).join(' '));
  }

  // Decode image off main thread
  const blob = new Blob([imageData], { type: 'image/png' });

  try {
    return await createImageBitmap(blob);
  } catch (error) {
    console.error('Failed to decode PNG data:', error);
    console.log('Image data length:', imageData.length);
    console.log('First 64 bytes:', Array.from(imageData.slice(0, 64)).map(b => b.toString(16).padStart(2, '0')).join(' '));

    // Return a 1x1 transparent image as fallback
    const canvas = new OffscreenCanvas(1, 1);
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, 1, 1);
    }
    return createImageBitmap(canvas);
  }
}

