              // the viewports to call applyAndRenderViewState
              console.log("Layer added successfully, ready to render.");
            } catch (e) {
              console.error("Failed to add layer:", e);
            }
          });

          return () => { unlisten(); };
        }, []); // Empty dependency array ensures this runs once on mount
        ```

This architecture is robust, scalable, and aligns well with the reactive nature of your frontend and the asynchronous capabilities of your backend.

