// --- Add Correlation ID Macro ---
#[macro_export]
macro_rules! new_request_span {
    ($name:literal) => {
        // Use tracing::info_span! which includes target/file/line info by default
        tracing::info_span!($name, request_id = %uuid::Uuid::new_v4())
    };
}
// --- End Correlation ID Macro ---

