                vol.get_at_coords(&[x, y, z]).map(|v| v as f32).unwrap_or(0.0)
            } else {
                0.0
            }
        },
        VolumeSendable::VolI32(vol, _) => {
            let dims = vol.space().dims();
            if voxel_coords[0] >= 0.0 && voxel_coords[0] < dims[0] as f32 &&
