#[command]
#[tracing::instrument(skip_all, err, name = "api.apply_and_render_view_state")]
async fn apply_and_render_view_state(
    view_state_json: String,
    state: State<'_, BridgeState>
) -> BridgeResult<Vec<u8>> {
    info!("Bridge: apply_and_render_view_state called");

    // Parse the ViewState JSON - simplified structure for now
    #[derive(Deserialize)]
    struct SimpleViewState {
        crosshair: CrosshairState,
        // Additional fields can be added as needed
    }

    #[derive(Deserialize)]
    struct CrosshairState {
        world_mm: [f32; 3],
        visible: bool,
    }

    let view_state: SimpleViewState = serde_json::from_str(&view_state_json)
        .map_err(|e| BridgeError::Input {
            code: 2016,
            details: format!("Failed to parse view state JSON: {}", e)
        })?;

    // Get render loop service
    let service_guard = state.render_loop_service.lock().await;
    let service_arc = service_guard.as_ref()
        .ok_or_else(|| BridgeError::ServiceNotInitialized { 
            code: 5006, 
            details: "GPU rendering service is not initialized. Please initialize the render loop first.".to_string() 
        })?;
    let mut service = service_arc.lock().await;

    // Apply crosshair position
    service.set_crosshair(view_state.crosshair.world_mm);

    // Get render target dimensions
    let (width, height) = service.get_render_target_size()
        .ok_or_else(|| BridgeError::Internal {
            code: 5021,
            details: "No render target created. Call create_offscreen_render_target first.".to_string()
        })?;

    info!("Render target dimensions: {}x{}", width, height);

    // Render and return image as PNG
    let rgba_data = service.render_to_buffer()
        .map_err(|e| BridgeError::GpuError { 
            code: 8011, 
            details: format!("Failed to render view state: {}", e) 
        })?;

    info!("Rendered RGBA data: {} bytes (expected {} for {}x{}x4)", 
          rgba_data.len(), width * height * 4, width, height);

    // Convert RGBA to PNG
    use image::{ImageBuffer, Rgba, ImageEncoder};
    use image::codecs::png::PngEncoder;
    use std::io::Cursor;

    let img_buffer: ImageBuffer<Rgba<u8>, Vec<u8>> = 
        ImageBuffer::from_raw(width, height, rgba_data)
            .ok_or_else(|| BridgeError::Internal {
                code: 5022,
                details: "Failed to create image buffer from RGBA data".to_string()
            })?;

    let mut png_data = Vec::new();
    let encoder = PngEncoder::new(Cursor::new(&mut png_data));
    encoder.write_image(
        img_buffer.as_raw(),
        width,
        height,
        image::ExtendedColorType::Rgba8
    ).map_err(|e| BridgeError::Internal {
        code: 5023,
        details: format!("Failed to encode PNG: {}", e)
    })?;

    info!("Bridge: apply_and_render_view_state completed, {} bytes", png_data.len());

    // Debug: Log first few bytes of PNG data
    if png_data.len() >= 8 {
        info!("PNG first 8 bytes: {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x} {:02x}",
              png_data[0], png_data[1], png_data[2], png_data[3],
              png_data[4], png_data[5], png_data[6], png_data[7]);
    }

    Ok(png_data)
}

// --- Plugin Creation ---
pub fn create_plugin<R: Runtime>() -> TauriPlugin<R> {
    plugin()
}

pub fn plugin<R: Runtime>() -> TauriPlugin<R> {
    Builder::new("api-bridge")
        .invoke_handler(generate_handler![
            load_file,
            world_to_voxel,
            get_timeseries_matrix,
            request_layer_gpu_resources,
            release_layer_gpu_resources,
            fs_list_directory,
            init_render_loop,
            create_offscreen_render_target,
            resize_canvas,
            update_frame_ubo,
            update_frame_for_synchronized_view,
            set_crosshair,
            // set_view_plane, // Removed - view plane info now encoded in frame vectors
            clear_render_layers,
            update_layer_opacity,
            update_layer_colormap,
            update_layer_intensity,
            update_layer_threshold,
            set_layer_mask,
            request_frame,
            render_frame,
            render_to_image,
            render_to_image_binary,
            apply_and_render_view_state,
            add_render_layer,
            patch_layer,
            sample_world_coordinate,
        ])
        .setup(|app, _| {
            // Initialize the bridge state
            let bridge_state = BridgeState::default();
            app.manage(bridge_state);
            Ok(())
        })
        .build()
}

